trait AwsCredentialManager {
  def getCredentialsProvider: AwsCredentialsProvider
  def validateCredentials(): Boolean
}

class SecureAwsCredentialManager(
    credentialSource: CredentialSource,
    region: Region = Region.US_EAST_1,
    secretName: Option[String] = None
) extends AwsCredentialManager {

  private val credentialsProvider: AwsCredentialsProvider = credentialSource match {
    case DefaultChain =>
      // Uses the default credential provider chain:
      // Environment variables -> System properties -> Web identity token ->
      // Shared credentials file -> EC2 instance profile / ECS container credentials
      DefaultCredentialsProvider.create()

    case EnvironmentVariables =>
      // Reads from AWS_ACCESS_KEY_ID and AWS_SECRET_ACCESS_KEY environment variables
      EnvironmentVariableCredentialsProvider.create()

    case SecretsManager =>
      // Bootstrap with default credentials to access Secrets Manager,
      // then retrieve the actual credentials from the secret
      loadCredentialsFromSecretsManager(region, secretName.getOrElse(
        throw new IllegalArgumentException("secretName is required for SecretsManager credential source")
      ))
  }

  private def loadCredentialsFromSecretsManager(
      region: Region,
      secretId: String
  ): AwsCredentialsProvider = {
    val smClient = SecretsManagerClient.builder()
      .region(region)
      .credentialsProvider(DefaultCredentialsProvider.create())
      .build()

    try {
      val request = GetSecretValueRequest.builder()
        .secretId(secretId)
        .build()

      val response = smClient.getSecretValue(request)
      val secretString = response.secretString()

      // Parse the secret JSON to extract credentials
      // Expected format: {"accessKeyId": "...", "secretAccessKey": "..."}
      val parsed = parseSecretJson(secretString)
      val accessKeyId = parsed.getOrElse("accessKeyId",
        throw new RuntimeException("accessKeyId not found in secret"))
      val secretAccessKey = parsed.getOrElse("secretAccessKey",
        throw new RuntimeException("secretAccessKey not found in secret"))

      val credentials = AwsBasicCredentials.create(accessKeyId, secretAccessKey)
      // Clear the parsed values from local scope as soon as possible
      StaticCredentialsProvider.create(credentials)
    } finally {
      smClient.close()
    }
  }

  private def parseSecretJson(json: String): Map[String, String] = {
    // Minimal JSON parsing without external dependency
    // In production, use a proper JSON library like circe or play-json
    val cleaned = json.trim.stripPrefix("{").stripSuffix("}")
    cleaned.split(",").map { pair =>
      val parts = pair.split(":", 2)
      val key = parts(0).trim.stripPrefix("\"").stripSuffix("\"")
      val value = parts(1).trim.stripPrefix("\"").stripSuffix("\"")
      key -> value
    }.toMap
  }

  override def getCredentialsProvider: AwsCredentialsProvider = credentialsProvider

  override def validateCredentials(): Boolean = {
    val stsClient = StsClient.builder()
      .region(region)
      .credentialsProvider(credentialsProvider)
      .build()

    try {
      val response = stsClient.getCallerIdentity(GetCallerIdentityRequest.builder().build())
      println(s"Credentials valid. Account: ${response.account()}, ARN: ${response.arn()}")
      true
    } catch {
      case e: Exception =>
        println(s"Credential validation failed: ${e.getMessage}")
        false
    } finally {
      stsClient.close()
    }
  }
}

class AwsS3Service(
    credentialManager: AwsCredentialManager,
    region: Region = Region.US_EAST_1
) {

  private lazy val s3Client: S3Client = S3Client.builder()
    .region(region)
    .credentialsProvider(credentialManager.getCredentialsProvider)
    .build()

  def listBuckets(): Try[List[String]] = Try {
    val response = s3Client.listBuckets(ListBucketsRequest.builder().build())
    response.buckets().asScala.map(_.name()).toList
  }

  def createBucket(bucketName: String): Try[Unit] = Try {
    val request = CreateBucketRequest.builder()
      .bucket(bucketName)
      .build()
    s3Client.createBucket(request)
    println(s"Bucket '$bucketName' created successfully.")
  }

  def deleteBucket(bucketName: String): Try[Unit] = Try {
    val request = DeleteBucketRequest.builder()
      .bucket(bucketName)
      .build()
    s3Client.deleteBucket(request)
    println(s"Bucket '$bucketName' deleted successfully.")
  }

  def listObjects(bucketName: String, prefix: Option[String] = None): Try[List[String]] = Try {
    val requestBuilder = ListObjectsV2Request.builder().bucket(bucketName)
    prefix.foreach(p => requestBuilder.prefix(p))
    val response = s3Client.listObjectsV2(requestBuilder.build())
    response.contents().asScala.map(_.key()).toList
  }

  def uploadFile(bucketName: String, key: String, filePath: Path): Try[Unit] = Try {
    val request = PutObjectRequest.builder()
      .bucket(bucketName)
      .key(key)
      .build()
    s3Client.putObject(request, filePath)
    println(s"File uploaded to s3://$bucketName/$key")
  }

  def uploadString(bucketName: String, key: String, content: String): Try[Unit] = Try {
    val request = PutObjectRequest.builder()
      .bucket(bucketName)
      .key(key)
      .build()
    s3Client.putObject(request, RequestBody.fromString(content))
    println(s"Content uploaded to s3://$bucketName/$key")
  }

  def downloadFile(bucketName: String, key: String, destinationPath: Path): Try[Unit] = Try {
    val request = GetObjectRequest.builder()
      .bucket(bucketName)
      .key(key)
      .build()
    s3Client.getObject(request, destinationPath)
    println(s"File downloaded from s3://$bucketName/$key to $destinationPath")
  }

  def close(): Unit = {
    s3Client.close()
  }
}

class AwsServiceFacade(
    credentialSource: CredentialSource = DefaultChain,
    region: Region = Region.US_EAST_1,
    secretName: Option[String] = None
) {

  private val credentialManager = new SecureAwsCredentialManager(
    credentialSource = credentialSource,
    region = region,
    secretName = secretName
  )

  lazy val s3: AwsS3Service = new AwsS3Service(credentialManager, region)

  def validateCredentials(): Boolean = credentialManager.validateCredentials()

  def shutdown(): Unit = {
    s3.close()
  }
}

